import type React from 'react';

import { cn } from '../utils/cn';

/**
 * Composable Scrollbox components with optional "fade" shadow at bottom.
 */
const ScrollBox = ({
  children,
  className,
  ...props
}: React.ComponentProps<'div'>) => {
  return (
    <div
      className={cn(
        'overflow-auto focus-visible:outline-none focus-visible:ring-2',
        className
      )}
      {...props}
    >
      {children}
    </div>
  );
};

/**
 * Adds a white-to-transparent fade at the bottom of the scroll box.
 */
const ScrollBoxShadowContainer = ({
  children,
  className,
  ...props
}: React.ComponentProps<'div'>) => {
  return (
    <div className="relative pb-3" {...props}>
      {children}
      <div
        className={cn(
          [
            'pointer-events-none absolute bottom-0 right-0 h-8',
            'w-full bg-gradient-to-t from-background to-transparent',
          ],
          className
        )}
      />
    </div>
  );
};

export { ScrollBox, ScrollBoxShadowContainer };
